"const fs = require('fs');
const readline = require('readline');
const path = require('path');

const logPath = '/Users/sahilpatel/.gemini/antigravity-ide/brain/95c2cdb5-9f4e-4753-9387-e792c2ce401a/.system_generated/logs/transcript.jsonl';

async function run() {
  const fileStream = fs.createReadStream(logPath);
  const rl = readline.createInterface({
    input: fileStream,
    crlfDelay: Infinity
  });

  let index = 0;
  for await (const line of rl) {
    index++;
    // We are looking for lines that contain product names like "Ganesh Rudraksha" or "7 Horses on Raw Pyrite Frame"
    // and have a large amount of content (indicating a full JSON printout of products).
    if (line.includes('Ganesh Rudraksha') && line.includes('description') && line.length > 5000) {
      console.log(`--- FOUND POTENTIAL JSON PRODUCT DATA ON LINE ${index} ---`);
      try {
        const parsed = JSON.parse(line);
        console.log('Step Index:', parsed.step_index);
        console.log('Type:', parsed.type);
        console.log('Source:', parsed.source);
        console.log('Line length:', line.length);

        // Write the full step contents to a file for analysis
        const outPath = path.join(__dirname, `step_${parsed.step_index}_dump.json`);
        fs.writeFileSync(outPath, JSON.stringify(parsed, null, 2));
        console.log(`Wrote dump to ${outPath}`);
      } catch (e) {
        console.error('Error parsing line:', e.message);
      }
    }
  }
  console.log('Finished scanning.');
}

run();
"
